mapper.select:
SELECT CustCode AS custCode, CustName AS custName, AptCode AS aptCode, BuildingCode AS buildingCode, FloorCode AS floorCode, RoomCode AS roomCode, CustPhone AS custPhone FROM ComCustomer
AptCode = #{aptCode}
ORDER BY AptCode, BuildingCode, FloorCode, RoomCode, CustName

SELECT COUNT(1)
FROM ComCustomer
WHERE AptCode = #{aptCode}
AND BuildingCode = #{buildingCode}
AND FloorCode = #{floorCode}
AND RoomCode = #{roomCode}
